def get_evens(nums):
    return [n for n in nums if n % 2 == 0]

The base case only catches n == 1, so calling the function with 0 or a negative number causes infinite recursion. Add a base case for 0 and reject negative inputs.

def factorial(n):
    if n < 0:
        raise ValueError("factorial is not defined for negative numbers")
    if n == 0 or n == 1:
        return 1
    return n * factorial(n - 1)

def is_palindrome(s):
    cleaned = ""
    for c in s:
        if c.isalnum():
            cleaned += c.lower()
    return cleaned == cleaned[::-1]

def fizzbuzz(n):
    result = []
    for i in range(1, n + 1):
        if i % 15 == 0:
            result.append('FizzBuzz')
        elif i % 3 == 0:
            result.append('Fizz')
        elif i % 5 == 0:
            result.append('Buzz')
        else:
            result.append(str(i))
    return result
